// Calculate P&L and format each position as a spreadsheet row
const positions = $input.all();
const timestamp = new Date().toISOString();
const rows = [];
let totalPortfolioValue = 0;

for (const item of positions) {
  const p = item.json;
  const size = Number(p.size || p.amount || 0);
  const avgPrice = Number(p.avgPrice || p.price || 0);
  const currentPrice = Number(p.currentPrice || p.curPrice || avgPrice);
  const market = p.market || p.question || p.title || 'Unknown';
  const outcome = p.outcome || p.side || 'Unknown';

  const costBasis = size * avgPrice;
  const currentValue = size * currentPrice;
  const cashPnl = currentValue - costBasis;
  const percentPnl = costBasis > 0 ? ((cashPnl / costBasis) * 100) : 0;

  totalPortfolioValue += currentValue;

  rows.push({
    json: {
      Timestamp: timestamp,
      Market: market,
      Outcome: outcome,
      Size: size.toFixed(2),
      'Avg Price': '$' + avgPrice.toFixed(4),
      'Current Price': '$' + currentPrice.toFixed(4),
      Value: '$' + currentValue.toFixed(2),
      'Cash P&L': (cashPnl >= 0 ? '+$' : '-$') + Math.abs(cashPnl).toFixed(2),
      'Percent P&L': percentPnl.toFixed(2) + '%',
      'Total Portfolio Value': ''
    }
  });
}

// Add a summary row
rows.push({
  json: {
    Timestamp: timestamp,
    Market: '--- TOTAL ---',
    Outcome: '',
    Size: '',
    'Avg Price': '',
    'Current Price': '',
    Value: '$' + totalPortfolioValue.toFixed(2),
    'Cash P&L': '',
    'Percent P&L': '',
    'Total Portfolio Value': '$' + totalPortfolioValue.toFixed(2)
  }
});

return rows;
